DOCUMENT();
############################################################ # Load Macros ############################################################ loadMacros( "PGstandard.pl", "PGML.pl", "AnswerFormatHelp.pl", "PGlateximage.pl", "contextForm.pl", "contextFraction.pl", "Pd.pl", "PGcourse.pl", ); COMMENT('Authored in PreTeXt');
############################################################ # Header ############################################################ TEXT(beginproblem());
############################################################ # PG Setup Code ############################################################ Context("LimitedFraction")->flags->set(requirePureFractions => 1, showMixedNumbers => 0); @x = random_subset(2, 1 .. 4, -4 .. -1); @y = random_subset(2, -4 .. -1, 1 .. 4); $m = Fraction(($y[1] - $y[0])/($x[1] - $x[0])); Context("Numeric"); Context()->noreduce('(-x)-y', '(-x)+y'); $f = Formula("$m (x - $x[0]) + $y[0]")->reduce;
$image_1 = createLaTeXImage(); $image_1->addToPreamble(latexImagePreamble()); $image_1->BEGIN_LATEX_IMAGE \begin{tikzpicture} \begin{axis}[ xmin=-10, xmax=10, ymin=-10, ymax=10, xtick={-5,0,5}, minor xtick={-9,...,9}, ytick={-5,0,5}, minor ytick={-9,...,9}, width=0.33\orccaprintwidth ] \addplot+[-,domain=-10:10,samples=2] {$f}; \end{axis} \end{tikzpicture}
END_LATEX_IMAGE
############################################################ # Body ############################################################
BEGIN_PGML Find the slope of the line given its graph.
>> [@image(insertGraph($image_1), width=>600)@]* <<
[_]{$m}{10}
END_PGML
